from collections import OrderedDict

class LRU:
    def __init__(self, cap:int):
        self.cap=cap
        self.d=OrderedDict()

    def get(self, k):
        if k not in self.d: return None
        self.d.move_to_end(k)
        return self.d[k]

    def put(self, k, v):
        if k in self.d: self.d.move_to_end(k)
        self.d[k]=v
        if len(self.d)>self.cap:
            self.d.popitem(last=False)

